/// Formats a double as a Python <c>float(...)</c> call for inclusion in generated
/// PySpark code. Wrapping in <c>float()</c> guarantees that
/// <c>createDataFrame</c> sees a Python <see langword="float"/> regardless of how the
/// numeric literal would otherwise be parsed — values like <c>0</c> or <c>1</c> would
/// be Python <see langword="int"/>s and silently rejected against a <c>DoubleType</c>
/// schema, causing the entire row to be dropped from the MERGE.
/// The <c>"R"</c> (round-trip) format specifier preserves full double precision and
/// invariant culture ensures decimal points (not commas) regardless of locale.
internal static string FormatDouble(double value)
{
    return FormattableString.Invariant($"float({value:R})");
}

